-- Demo seed data: vendors, categories, payment methods, and bills across
-- every status in bill_status (draft, awaiting_approval, approved, scheduled,
-- initiated, paid, archived, rejected, payment_failed) with matching payments
-- and activity log entries. All rows use fixed UUIDs so the migration is
-- idempotent via ON CONFLICT (id) DO NOTHING; re-running drizzle-kit migrate
-- on a database that already has them is a no-op.
--
-- A dedicated seed user owns the demo data.
INSERT INTO users (id, mock_user_key, email, full_name, role)
VALUES (
  '00000000-0000-0000-0000-000000000001',
  'seed_demo_user_v1',
  'seed-demo@silver.local',
  'Demo Seed User',
  'employee'
)
ON CONFLICT (mock_user_key) DO NOTHING;--> statement-breakpoint

